# Let's write a quick script to test the math of ARS.

get_z <- function(x, h_val, h_prime, domain) {
  k <- length(x)
  z <- numeric(k + 1)
  z[1] <- domain[1]
  z[k + 1] <- domain[2]

  if (k > 1) {
    for (i in 1:(k - 1)) {
      # Intersection of L_i and L_{i+1}
      num <- h_val[i + 1] - h_val[i] - x[i + 1] * h_prime[i + 1] + x[i] * h_prime[i]
      den <- h_prime[i] - h_prime[i + 1]
      if (den == 0) {
        z[i + 1] <- (x[i] + x[i + 1]) / 2 # fallback if derivatives are equal
      } else {
        z[i + 1] <- num / den
      }
    }
  }
  return(z)
}

# Test get_z
x <- c(-1, 1)
h_val <- dnorm(x, log=TRUE)
h_prime <- -x
get_z(x, h_val, h_prime, c(-Inf, Inf))

compute_masses <- function(x, h_val, h_prime, z) {
  k <- length(x)
  M <- numeric(k)
  for (i in 1:k) {
    if (abs(h_prime[i]) < 1e-8) {
      M[i] <- exp(h_val[i]) * (z[i+1] - z[i])
    } else {
      term1 <- h_prime[i] * (z[i+1] - x[i])
      term2 <- h_prime[i] * (z[i] - x[i])

      val1 <- ifelse(z[i+1] == Inf, 0, exp(term1))
      val2 <- ifelse(z[i] == -Inf, 0, exp(term2))

      M[i] <- (exp(h_val[i]) / h_prime[i]) * (val1 - val2)
    }
  }
  return(M)
}

