sample_upper <- function(x, h_val, h_prime, z, M) {
  p <- M / sum(M)
  i <- sample(1:length(M), size=1, prob=p)

  u <- runif(1)
  if (abs(h_prime[i]) < 1e-8) {
    x_star <- z[i] + u * (z[i+1] - z[i])
