eval_u <- function(x_star, x, h_val, h_prime, z) {
  i <- which(z[-length(z)] <= x_star & z[-1] >= x_star)[1]
  if (is.na(i)) {
    # Could happen due to floating point inaccuracies if x_star is exactly on a boundary
    if (x_star <= z[1]) i <- 1
    else if (x_star >= z[length(z)]) i <- length(x)
  }
  return(h_val[i] + h_prime[i] * (x_star - x[i]))
}

eval_l <- function(x_star, x, h_val) {
  if (x_star < x[1] || x_star > x[length(x)]) {
    return(-Inf)
  }
  # Find interval
  j <- which(x[-length(x)] <= x_star & x[-1] >= x_star)[1]
  if (is.na(j)) {
    # exactly on boundary
    if (x_star == x[1]) return(h_val[1])
    if (x_star == x[length(x)]) return(h_val[length(x)])
  }
  slope <- (h_val[j+1] - h_val[j]) / (x[j+1] - x[j])
  return(h_val[j] + slope * (x_star - x[j]))
}

insert_point <- function(x_star, h_star, hp_star, x, h_val, h_prime) {
  # Find position
  j <- sum(x < x_star)

  # Log-concavity check on derivatives
  if (j > 0 && h_prime[j] < hp_star - 1e-8) {
    stop("Density is not log-concave: derivative is not monotonically decreasing.")
  }
  if (j < length(x) && hp_star < h_prime[j+1] - 1e-8) {
    stop("Density is not log-concave: derivative is not monotonically decreasing.")
  }

  # Insert
  x <- c(x[seq_len(j)], x_star, if (j < length(x)) x[(j+1):length(x)] else NULL)
  h_val <- c(h_val[seq_len(j)], h_star, if (j < length(h_val)) h_val[(j+1):length(h_val)] else NULL)
  h_prime <- c(h_prime[seq_len(j)], hp_star, if (j < length(h_prime)) h_prime[(j+1):length(h_prime)] else NULL)

  return(list(x=x, h_val=h_val, h_prime=h_prime))
}

init_points <- function(h_func, hp_func, domain) {
  pts <- numeric(0)
  start_x <- 0
  if (domain[1] > -Inf && domain[2] < Inf) {
    start_x <- (domain[1] + domain[2]) / 2
  } else if (domain[1] > -Inf) {
    start_x <- max(0, domain[1] + 1)
  } else if (domain[2] < Inf) {
    start_x <- min(0, domain[2] - 1)
  }

  pos_pt <- NULL
  if (domain[1] == -Inf) {
    x_test <- start_x
    step <- 1
    for (i in 1:100) {
      if (h_func(x_test) > -Inf && hp_func(x_test) > 0) {
        pos_pt <- x_test
        break
      }
      x_test <- x_test - step
      step <- step * 2
    }
    if (is.null(pos_pt)) stop("Could not find a point with positive derivative for left unbound domain.")
    pts <- c(pts, pos_pt)
  }

  neg_pt <- NULL
  if (domain[2] == Inf) {
    x_test <- start_x
    step <- 1
    for (i in 1:100) {
      if (h_func(x_test) > -Inf && hp_func(x_test) < 0) {
        neg_pt <- x_test
        break
      }
      x_test <- x_test + step
      step <- step * 2
    }
    if (is.null(neg_pt)) stop("Could not find a point with negative derivative for right unbound domain.")
    pts <- c(pts, neg_pt)
  }

  if (length(pts) < 2) {
    if (length(pts) == 1) {
      x_test <- start_x
      for(i in 1:100) {
        if(x_test != pts[1] && h_func(x_test) > -Inf) break
        x_test <- x_test + 0.1
      }
      pts <- c(pts, x_test)
    } else {
      pts <- c(domain[1] + 0.3 * (domain[2] - domain[1]), domain[1] + 0.7 * (domain[2] - domain[1]))
    }
  }

  return(sort(pts))
}

