#' Adaptive Rejection Sampler (ARS)
#'
#' @param n Number of samples to generate
#' @param f A function that calculates the (possibly unnormalized) density
#' @param domain A vector of length 2 representing the support of the distribution
#' @param x_init An optional vector of initial points
#' @param ... Additional arguments passed to f
#' @return A vector of n samples
ars <- function(n, f, domain=c(-Inf, Inf), x_init=NULL, ...) {
  if (!is.numeric(n) || n <= 0 || n %% 1 != 0) {
    stop("n must be a positive integer.")
  }
  if (!is.function(f)) {
    stop("f must be a function.")
  }
  if (length(domain) != 2 || domain[1] >= domain[2]) {
    stop("domain must be a vector of length 2 with domain[1] < domain[2].")
  }

  h <- function(x) {
    val <- log(f(x, ...))
    if (is.nan(val) || is.na(val)) return(-Inf)
    return(val)
  }

  hp <- function(x) {
    eps <- 1e-5
    x_plus <- min(x + eps, domain[2])
    x_minus <- max(x - eps, domain[1])
    if (x_plus == x_minus) return(0)
    return((h(x_plus) - h(x_minus)) / (x_plus - x_minus))
  }

  if (is.null(x_init)) {
    x <- init_points(h, hp, domain)
  } else {
    x <- sort(x_init)
    if (length(x) < 2) {
      stop("x_init must have at least 2 points.")
    }
  }

  h_val <- sapply(x, h)
  if (any(h_val == -Inf)) stop("Initial points must have positive density.")
  h_prime <- sapply(x, hp)

  if (domain[1] == -Inf && h_prime[1] <= 0) {
    stop("For left-unbounded domain, the leftmost initial point must have a positive derivative.")
  }
  if (domain[2] == Inf && h_prime[length(h_prime)] >= 0) {
    stop("For right-unbounded domain, the rightmost initial point must have a negative derivative.")
  }

  if (length(x) > 1) {
    for (i in 1:(length(x)-1)) {
      if (h_prime[i] < h_prime[i+1] - 1e-3) { # increased tolerance for numerical diff
        stop("Density is not log-concave: derivative is not monotonically decreasing.")
      }
    }
  }

  z <- get_z(x, h_val, h_prime, domain)
  M <- compute_masses(x, h_val, h_prime, z)

  samples <- numeric(n)
  count <- 0

  while (count < n) {
    res <- sample_upper(x, h_val, h_prime, z, M)
    x_star <- res$x

    if (is.nan(x_star) || is.na(x_star) || x_star < domain[1] || x_star > domain[2]) next

    w <- runif(1)
    u_val <- eval_u(x_star, x, h_val, h_prime, z)
    l_val <- eval_l(x_star, x, h_val)

    accepted <- FALSE
    h_star <- NULL
    hp_star <- NULL

    if (log(w) <= l_val - u_val) {
      accepted <- TRUE
    } else {
      h_star <- h(x_star)
      if (h_star > u_val + 1e-4) {
         stop("Density is not log-concave: function value exceeds upper envelope.")
      }
      if (log(w) <= h_star - u_val) {
        accepted <- TRUE
      }
      hp_star <- hp(x_star)
    }

    if (accepted) {
      count <- count + 1
      samples[count] <- x_star
    }

    if (!is.null(h_star)) {
      insert_res <- insert_point(x_star, h_star, hp_star, x, h_val, h_prime)
      if (length(insert_res$x) > length(x)) {
        x <- insert_res$x
        h_val <- insert_res$h_val
        h_prime <- insert_res$h_prime
        z <- get_z(x, h_val, h_prime, domain)
        M <- compute_masses(x, h_val, h_prime, z)
      }
    }
  }

  return(samples)
}

