      term2 <- h_prime[i] * (z[i] - x[i])

      val1 <- ifelse(z[i+1] == Inf, 0, exp(term1))
      val2 <- ifelse(z[i] == -Inf, 0, exp(term2))

      M[i] <- (exp(h_shift) / h_prime[i]) * (val1 - val2)
    }
  }
  return(M)
}

sample_upper <- function(x, h_val, h_prime, z, M) {
  p <- M / sum(M)
  i <- sample(1:length(M), size=1, prob=p)
  u <- runif(1)
  if (abs(h_prime[i]) < 1e-8) {
    x_star <- z[i] + u * (z[i+1] - z[i])
  } else {
    term1 <- h_prime[i] * (z[i+1] - x[i])
    term2 <- h_prime[i] * (z[i] - x[i])
    val1 <- ifelse(z[i+1] == Inf, 0, exp(term1))
    val2 <- ifelse(z[i] == -Inf, 0, exp(term2))
    val <- u * (val1 - val2) + val2
    x_star <- x[i] + (1 / h_prime[i]) * log(val)
  }
  return(list(x=x_star, i=i))
}

eval_u <- function(x_star, x, h_val, h_prime, z) {
  i <- which(z[-length(z)] <= x_star & z[-1] >= x_star)[1]
  if (is.na(i)) {
    if (x_star <= z[1]) i <- 1
    else if (x_star >= z[length(z)]) i <- length(x)
  }
  return(h_val[i] + h_prime[i] * (x_star - x[i]))
}

eval_l <- function(x_star, x, h_val) {
  if (x_star < x[1] || x_star > x[length(x)]) {
    return(-Inf)
  }
  j <- which(x[-length(x)] <= x_star & x[-1] >= x_star)[1]
  if (is.na(j)) {
    if (x_star == x[1]) return(h_val[1])
    if (x_star == x[length(x)]) return(h_val[length(x)])
  }
  slope <- (h_val[j+1] - h_val[j]) / (x[j+1] - x[j])
  return(h_val[j] + slope * (x_star - x[j]))
}

insert_point <- function(x_star, h_star, hp_star, x, h_val, h_prime) {
  j <- sum(x < x_star)

  tol <- 1e-2 # higher tolerance for numerical derivatives
  if (j > 0 && h_prime[j] < hp_star - tol) {
    stop(sprintf("Density is not log-concave: derivative is not monotonically decreasing. hp_star: %f, h_prime[%d]: %f", hp_star, j, h_prime[j]))
  }
  if (j < length(x) && hp_star < h_prime[j+1] - tol) {
    stop(sprintf("Density is not log-concave: derivative is not monotonically decreasing. hp_star: %f, h_prime[%d]: %f", hp_star, j+1, h_prime[j+1]))
  }

  if (j > 0 && abs(x_star - x[j]) < 1e-4) return(list(x=x, h_val=h_val, h_prime=h_prime))
  if (j < length(x) && abs(x_star - x[j+1]) < 1e-4) return(list(x=x, h_val=h_val, h_prime=h_prime))

  x <- c(x[seq_len(j)], x_star, if (j < length(x)) x[(j+1):length(x)] else NULL)
  h_val <- c(h_val[seq_len(j)], h_star, if (j < length(h_val)) h_val[(j+1):length(h_val)] else NULL)
  h_prime <- c(h_prime[seq_len(j)], hp_star, if (j < length(h_prime)) h_prime[(j+1):length(h_prime)] else NULL)

  return(list(x=x, h_val=h_val, h_prime=h_prime))
}

#' Adaptive Rejection Sampler (ARS)
#'
#' @param n Number of samples to generate
#' @param f A function that calculates the (possibly unnormalized) density
#' @param domain A vector of length 2 representing the support of the distribution
#' @param x_init An optional vector of initial points
#' @param ... Additional arguments passed to f
#' @return A vector of n samples
ars <- function(n, f, domain=c(-Inf, Inf), x_init=NULL, ...) {
  if (!is.numeric(n) || n <= 0 || n %% 1 != 0) {
    stop("n must be a positive integer.")
  }
  if (!is.function(f)) {
    stop("f must be a function.")
  }
  if (length(domain) != 2 || domain[1] >= domain[2]) {
    stop("domain must be a vector of length 2 with domain[1] < domain[2].")
  }

  h <- function(x) {
    val <- log(f(x, ...))
    if (is.nan(val) || is.na(val)) return(-Inf)
    return(val)
  }

  hp <- function(x) {
    eps <- 1e-5
    x_plus <- min(x + eps, domain[2])
    x_minus <- max(x - eps, domain[1])
    if (x_plus == x_minus) return(0)
    return((h(x_plus) - h(x_minus)) / (x_plus - x_minus))
  }

  if (is.null(x_init)) {
    x <- init_points(h, hp, domain)
  } else {
    x <- sort(x_init)
    if (length(x) < 2) {
      stop("x_init must have at least 2 points.")
    }
  }

  h_val <- sapply(x, h)
  if (any(h_val == -Inf)) stop("Initial points must have positive density.")
  h_prime <- sapply(x, hp)

  if (domain[1] == -Inf && h_prime[1] <= 0) {
    stop("For left-unbounded domain, the leftmost initial point must have a positive derivative.")
  }
  if (domain[2] == Inf && h_prime[length(h_prime)] >= 0) {
    stop("For right-unbounded domain, the rightmost initial point must have a negative derivative.")
  }

  if (length(x) > 1) {
    for (i in 1:(length(x)-1)) {
      if (h_prime[i] < h_prime[i+1] - 1e-2) {
        stop("Density is not log-concave: derivative is not monotonically decreasing.")
      }
    }
  }

  z <- get_z(x, h_val, h_prime, domain)
  M <- compute_masses(x, h_val, h_prime, z)

  samples <- numeric(n)
  count <- 0

  while (count < n) {
    res <- sample_upper(x, h_val, h_prime, z, M)
    x_star <- res$x

    if (is.nan(x_star) || is.na(x_star) || x_star < domain[1] || x_star > domain[2]) next

    w <- runif(1)
    u_val <- eval_u(x_star, x, h_val, h_prime, z)
    l_val <- eval_l(x_star, x, h_val)

    accepted <- FALSE
    h_star <- NULL
    hp_star <- NULL

    if (log(w) <= l_val - u_val) {
      accepted <- TRUE
    } else {
      h_star <- h(x_star)
      if (h_star > u_val + 1e-2) { # numerical tolerance
         stop(sprintf("Density is not log-concave: function value exceeds upper envelope. h_star=%f, u_val=%f", h_star, u_val))
      }
      if (log(w) <= h_star - u_val) {
        accepted <- TRUE
      }
      hp_star <- hp(x_star)
    }

    if (accepted) {
      count <- count + 1
      samples[count] <- x_star
    }

    if (!is.null(h_star)) {
      insert_res <- insert_point(x_star, h_star, hp_star, x, h_val, h_prime)
      if (length(insert_res$x) > length(x)) {
        x <- insert_res$x
        h_val <- insert_res$h_val
        h_prime <- insert_res$h_prime
        z <- get_z(x, h_val, h_prime, domain)
        M <- compute_masses(x, h_val, h_prime, z)
      }
    }
  }

  return(samples)
}

test <- function() {
  cat("Running tests for ARS implementation...\n\n")

  # Test 1: Standard Normal Distribution
  cat("Test 1: Normal Distribution N(0, 1)\n")
  f_norm <- function(x) dnorm(x)
  n_samples <- 10000
  norm_samples <- tryCatch({
    ars(n_samples, f_norm)
  }, error = function(e) {
    cat("Error during normal sampling:", e$message, "\n")
    return(NULL)
  })

  if (!is.null(norm_samples)) {
    m <- mean(norm_samples)
    s <- sd(norm_samples)
    pass <- abs(m - 0) < 0.05 && abs(s - 1) < 0.05
    status <- ifelse(pass, "PASS", "FAIL")
    cat(sprintf("NORMAL_TEST: %s (Mean: %.4f, SD: %.4f)\n", status, m, s))

    # Save samples
    write.table(norm_samples, "/app/normal_samples.txt", row.names=FALSE, col.names=FALSE)
  } else {
    cat("NORMAL_TEST: FAIL\n")
  }

  cat("\n")

  # Test 2: Exponential Distribution
  cat("Test 2: Exponential Distribution Exp(1)\n")
  f_exp <- function(x) dexp(x)
  exp_samples <- tryCatch({
    ars(n_samples, f_exp, domain=c(0, Inf))
  }, error = function(e) {
    cat("Error during exponential sampling:", e$message, "\n")
    return(NULL)
  })

  if (!is.null(exp_samples)) {
    m <- mean(exp_samples)
    s <- sd(exp_samples)
    pass <- abs(m - 1) < 0.05 && abs(s - 1) < 0.05
    status <- ifelse(pass, "PASS", "FAIL")
    cat(sprintf("EXPONENTIAL_TEST: %s (Mean: %.4f, SD: %.4f)\n", status, m, s))

    # Save samples
    write.table(exp_samples, "/app/exponential_samples.txt", row.names=FALSE, col.names=FALSE)
  } else {
    cat("EXPONENTIAL_TEST: FAIL\n")
  }

  cat("\n")

  # Test 3: Log-concavity check with non-log-concave function (Student's t, df=1 is Cauchy)
  cat("Test 3: Non-log-concave function rejection (Cauchy)\n")
  f_cauchy <- function(x) dt(x, df=1)
  cauchy_samples <- tryCatch({
    ars(100, f_cauchy)
    "FAIL" # Should not reach here
  }, error = function(e) {
    "PASS" # Expected to throw error
  })
  cat(sprintf("NON_LOG_CONCAVE_TEST: %s\n", cauchy_samples))
}

